#include <iostream>\n#include <vector>\n\nclass Graph {\n public:\n  explicit Graph(int n) : n_(n), comps_count_(n) {\n    r_.resize(n_, 0);\n    p_.resize(n_);\n    for (int i = 0; i < n_; i++) {\n      p_[i] = i;\n    }\n  }\n\n  void AddEdge(int a, int b, int w) {\n    a = Get(--a);\n    b = Get(--b);\n    if (a == b) {\n      return;\n    }\n    Union(a, b);\n    weight_ += w;\n    comps_count_--;\n  }\n\n  bool IsOneComp() {\n    return comps_count_ == 1;\n  }\n\n  int GetWeight() {\n    return weight_;\n  }\n\n private:\n  int Get(int v) {\n    if (v != p_[v]) {\n      p_[v] = Get(p_[v]);\n    }\n    return p_[v];\n  }\n\n  void Union(int a, int b) {\n    if (r_[a] > r_[b]) {\n      std::swap(a, b);\n    }\n    if (r_[a] == r_[b]) {\n      r_[b]++;\n    }\n    p_[a] = b;\n  }\n\n  int n_;\n  int comps_count_;\n  int weight_ = 0;\n  std::vector<int> p_;\n  std::vector<int> r_;\n};\n\nint main() {\n  // magic code\n  std::ios_base::sync_with_stdio(false);\n  std::cin.tie(nullptr);\n  std::cout.tie(nullptr);\n\n  int n = 0;\n  int m = 0;\n  std::cin >> n >> m;\n\n  Graph g(n);\n  for (int i = 0; i < m; i++) {\n    int a = 0;\n    int b = 0;\n    int w = 0;\n\n    std::cin >> a >> b >> w;\n    g.AddEdge(a, b, w);\n    if (g.IsOneComp()) {\n      break;\n    }\n  }\n  std::cout << g.GetWeight() << '\\n';\n  return 0;\n}